#!/usr/bin/perl
use strict;
use warnings;
use Digest::MD5 qw(md5_hex);
use Crypt::CBC;

# Fungsi untuk mengenkripsi data
sub enkripsi_data {
    my ($data) = @_;
    my $key = "kunci_rahasia";  # Ganti dengan kunci rahasia Anda
    my $cipher = Crypt::CBC->new(
        -key   => $key,
        -header => 'none',
        -iv    => '0123456789012345',
    );
    my $enkripsi = $cipher->encrypt($data);
    return $enkripsi;
}

# Fungsi untuk mendekripsi data
sub dekripsi_data {
    my ($data) = @_;
    my $key = "kunci_rahasia";  # Ganti dengan kunci rahasia Anda
    my $cipher = Crypt::CBC->new(
        -key   => $key,
        -header => 'none',
        -iv    => '0123456789012345',
    );
    my $dekripsi = $cipher->decrypt($data);
    return $dekripsi;
}

# Fungsi untuk mengenkripsi dan menyimpan data ke file
sub simpan_data {
    my ($data) = @_;
    my $enkripsi = enkripsi_data($data);
    open(my $fh, '>', 'data.txt') or die "Tidak dapat membuka file: $!";
    print $fh $enkripsi;
    close $fh;
}

# Fungsi untuk membaca dan mendekripsi data dari file
sub baca_data {
    open(my $fh, '<', 'data.txt') or die "Tidak dapat membuka file: $!";
    my $data = <$fh>;
    close $fh;
    my $dekripsi = dekripsi_data($data);
    return $dekripsi;
}

